class AlgorithmStatsTracker{constructor(){this.stats=new Map,this.sessionId=Date.now()}recordExecution(t,s,u,a={}){this.stats.has(t)||this.stats.set(t,{totalRuns:0,successfulRuns:0,totalExecutionTime:0,avgSuccessRate:0,lastRun:null,history:[]});const e=this.stats.get(t);return e.totalRuns++,s&&e.successfulRuns++,e.totalExecutionTime+=u,e.avgSuccessRate=(e.successfulRuns/e.totalRuns*100).toFixed(1),e.lastRun={success:s,executionTime:u,details:a,timestamp:new Date().toISOString()},e.history.push(e.lastRun),e.history.length>20&&e.history.shift(),this.getAlgorithmStats(t)}getAlgorithmStats(t){const s=this.stats.get(t);return s?{name:t,totalRuns:s.totalRuns,successfulRuns:s.successfulRuns,failedRuns:s.totalRuns-s.successfulRuns,successRate:s.avgSuccessRate+"%",avgTime:(s.totalExecutionTime/s.totalRuns).toFixed(2)+"ms",lastRun:s.lastRun}:null}getAllStats(){const t=[];return this.stats.forEach((s,u)=>{t.push(this.getAlgorithmStats(u))}),t}getSummary(){let t=0,s=0,u=0;return this.stats.forEach(a=>{t+=a.totalRuns,s+=a.successfulRuns,u++}),{algorithmsUsed:u,totalExecutions:t,successfulExecutions:s,overallSuccessRate:t>0?(s/t*100).toFixed(1)+"%":"N/A",sessionId:this.sessionId}}reset(){this.stats.clear(),this.sessionId=Date.now()}export(){return JSON.stringify({sessionId:this.sessionId,summary:this.getSummary(),algorithms:this.getAllStats()},null,2)}}typeof window<"u"&&(window.AlgorithmStatsTracker=AlgorithmStatsTracker);
